display_template.css:
.overview { display:grid; grid-template-columns:1fr 1fr 1fr; gap:8px; margin-bottom:16px; padding:12px; background:#27272a; border-radius:8px; }
.ov-item { display:flex; align-items:center; gap:8px; }
.ov-label { font-size:11px; color:#71717a; min-width:70px; }
.ov-value { font-size:13px; }
.grid { display:grid; grid-template-columns:1fr 1fr; gap:12px; }
.card { background:#27272a; border-radius:8px; padding:12px; border:1px solid #3f3f46; }
.card-hdr { display:flex; align-items:center; justify-content:space-between; margin-bottom:8px; font-weight:600; font-size:13px; }
.stat { font-size:12px; color:#a1a1aa; margin-bottom:8px; }
.badge { display:inline-block; padding:2px 8px; border-radius:4px; font-size:11px; font-weight:600; text-transform:uppercase; }
table { width:100%; border-collapse:collapse; font-size:12px; }
th { text-align:left; padding:4px 8px; color:#a1a1aa; border-bottom:1px solid #3f3f46; font-weight:500; }
td { padding:4px 8px; border-bottom:1px solid #27272a; }
td.cmd { max-width:200px; overflow:hidden; text-overflow:ellipsis; white-space:nowrap; }
tr:hover td { background:#3f3f4620; }
